#include <stdio.h>
#include <stdlib.h>
#include <string.h>

/* Simple open‑addressing hash set for 32‑bit integers */
#define TABLE_SIZE 200003  // a prime larger than maximum possible distinct nodes
static int table[TABLE_SIZE];
static char used[TABLE_SIZE];

static unsigned int hash_int(int x) {
    unsigned int h = (unsigned int)x;
    h ^= h >> 16;
    h *= 0x7feb352dU;
    h ^= h >> 15;
    return h;
}

static void clear_set() {
    memset(used, 0, sizeof(used));
}

static int insert(int x) {
    unsigned int idx = hash_int(x) % TABLE_SIZE;
    while (used[idx]) {
        if (table[idx] == x) return 0; // already present
        idx = (idx + 1) % TABLE_SIZE;
    }
    used[idx] = 1;
    table[idx] = x;
    return 1; // new insertion
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int M;
        scanf("%d", &M);
        clear_set();
        int distinct = 0;
        for (int i = 0; i < M; ++i) {
            int parent, child;
            char rel;
            scanf("%d %d %c", &parent, &child, &rel);
            distinct += insert(parent);
            distinct += insert(child);
        }
        printf("%d\n", distinct);
    }
    return 0;
}

